import{_ as a,C as n,o as r,c as i,a3 as l,E as c,w as p,j as e,a as o}from"./chunks/framework.BVmBWEBf.js";const w=JSON.parse('{"title":"Projects & Snapshots","description":"","frontmatter":{},"headers":[],"relativePath":"concepts/projects-and-snapshots.md","filePath":"concepts/projects-and-snapshots.md"}'),h={name:"concepts/projects-and-snapshots.md"};function d(u,t,m,g,f,j){const s=n("ManualRelated");return r(),i("div",null,[t[1]||(t[1]=l('<h1 id="projects-snapshots" tabindex="-1">Projects &amp; Snapshots <a class="header-anchor" href="#projects-snapshots" aria-label="Permalink to &quot;Projects &amp; Snapshots&quot;">​</a></h1><h2 id="project" tabindex="-1">Project <a class="header-anchor" href="#project" aria-label="Permalink to &quot;Project&quot;">​</a></h2><p>A <strong>project</strong> holds everything about one performance setup:</p><ul><li>32 knobs and all macro mappings</li><li>Up to <strong>8 racks</strong> (MIDI device chains)</li><li>16 LFO configurations and assignments</li><li>Snapshots for scene recall within the project</li></ul><p>Use <strong>Main Menu → Projects → Projects List</strong> to create, load, rename, or delete projects. See <a href="./../projects/">Projects</a> for save and list workflows.</p><p><strong>Typical workflow:</strong></p><ol><li>Create or load a project from <strong>Main Menu → Projects → Projects List</strong>.</li><li>Build racks, macros, and LFO routing.</li><li><strong>Save Project</strong> when you want changes to survive power-off.</li><li>Use <strong>Save As</strong> on the list side menu to fork a copy under a new name.</li></ol><p>Switching projects with unsaved edits may prompt you to save or discard.</p><h2 id="snapshot" tabindex="-1">Snapshot <a class="header-anchor" href="#snapshot" aria-label="Permalink to &quot;Snapshot&quot;">​</a></h2><p>A snapshot captures the <strong>current state</strong> of the active project — knob values, device parameters, bypass states — for instant recall during a set.</p><p><strong>Use snapshots when:</strong></p><ul><li>You need fast scene changes (intro / drop / outro) within one project.</li><li>You want to experiment, then jump back to a known point.</li></ul><p><strong>Use Save Project when:</strong></p><ul><li>You changed structure (new devices, macro modes, LFO wiring) and want it after power off.</li></ul><div class="warning custom-block"><p class="custom-block-title">Coming soon</p><p>Full snapshot documentation (list, take, recall, rename, delete) is being updated for the latest firmware. See <a href="./../snapshots/">Snapshots</a> for the menu location.</p></div><div class="tip custom-block"><p class="custom-block-title">TIP</p><ol><li>Build and <strong>Save Project</strong> once per song or set.</li><li>Use <strong>snapshots</strong> for sections within that set.</li><li><strong>Save As</strong> on the Projects List to fork a variation under another name.</li></ol></div>',16)),c(s,null,{default:p(()=>[...t[0]||(t[0]=[e("ul",null,[e("li",null,[e("a",{href:"./../projects/"},"Projects"),o(" — Create, load, rename, and save projects")]),e("li",null,[e("a",{href:"./../snapshots/"},"Snapshots"),o(" — Snapshot menu location")]),e("li",null,[e("a",{href:"./rack-chains"},"Rack chains"),o(" — Racks and device chains in a project")])],-1)])]),_:1})])}const k=a(h,[["render",d]]);export{w as __pageData,k as default};
